import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";

export default function Messages() {
  const [user, setUser] = useState(null);
  const [chatUsers, setChatUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    const { data } = await supabase.auth.getUser();
    const currentUser = data?.user;

    if (!currentUser) return;

    setUser(currentUser);
    fetchChatUsers(currentUser.id);
  };

  // ✅ build chat list from followers + following + existing messages
  const fetchChatUsers = async (userId) => {
    // people who follow me
    const { data: followersData } = await supabase
      .from("follows")
      .select("follower_id")
      .eq("following_id", userId);

    // people I follow
    const { data: followingData } = await supabase
      .from("follows")
      .select("following_id")
      .eq("follower_id", userId);

    // people already in conversation with me
    const { data: sentMsgs } = await supabase
      .from("messages")
      .select("receiver_id")
      .eq("sender_id", userId);

    const { data: receivedMsgs } = await supabase
      .from("messages")
      .select("sender_id")
      .eq("receiver_id", userId);

    const ids = [
      ...(followersData || []).map((f) => f.follower_id),
      ...(followingData || []).map((f) => f.following_id),
      ...(sentMsgs || []).map((m) => m.receiver_id),
      ...(receivedMsgs || []).map((m) => m.sender_id),
    ];

    const uniqueIds = [...new Set(ids)].filter((id) => id !== userId);

    if (uniqueIds.length === 0) {
      setChatUsers([]);
      return;
    }

    const { data: profiles, error } = await supabase
      .from("profiles")
      .select("id, name")
      .in("id", uniqueIds);

    if (error) {
      console.log("CHAT USERS ERROR:", error.message);
      return;
    }

    setChatUsers(profiles || []);
  };

  const fetchMessages = async (otherUserId) => {
    if (!user) return;

    const { data, error } = await supabase
      .from("messages")
      .select("*")
      .or(
        `and(sender_id.eq.${user.id},receiver_id.eq.${otherUserId}),and(sender_id.eq.${otherUserId},receiver_id.eq.${user.id})`
      )
      .order("created_at", { ascending: true });

    if (error) {
      console.log("MESSAGES ERROR:", error.message);
      return;
    }

    setMessages(data || []);
  };

  const sendMessage = async () => {
    if (!text.trim() || !selectedUser || !user) return;

    const { error } = await supabase.from("messages").insert([
      {
        sender_id: user.id,
        receiver_id: selectedUser.id,
        content: text,
      },
    ]);

    if (error) {
      console.log("SEND ERROR:", error.message);
      return;
    }

    setText("");
    fetchMessages(selectedUser.id);
    fetchChatUsers(user.id);
  };

  return (
    <div style={{ display: "flex", height: "80vh" }}>
      {/* LEFT */}
      <div style={{ width: "30%", borderRight: "1px solid gray", padding: "10px" }}>
        <h3>Chats</h3>

        {chatUsers.length === 0 ? (
          <p>No chats yet</p>
        ) : (
          chatUsers.map((u) => (
            <div
              key={u.id}
              onClick={() => {
                setSelectedUser(u);
                fetchMessages(u.id);
              }}
              style={{
                padding: "10px",
                cursor: "pointer",
                borderBottom: "1px solid gray",
              }}
            >
              👤 {u.name || "User"}
            </div>
          ))
        )}
      </div>

      {/* RIGHT */}
      <div style={{ flex: 1, padding: "10px" }}>
        {selectedUser ? (
          <>
            <h3>Chat with {selectedUser.name}</h3>

            <div style={{ height: "60vh", overflowY: "auto", marginBottom: "10px" }}>
              {messages.map((msg) => (
                <div
                  key={msg.id}
                  style={{
                    textAlign: msg.sender_id === user.id ? "right" : "left",
                    margin: "6px 0",
                  }}
                >
                  <span
                    style={{
                      background: msg.sender_id === user.id ? "#4f46e5" : "#555",
                      color: "white",
                      padding: "8px 12px",
                      borderRadius: "10px",
                      display: "inline-block",
                    }}
                  >
                    {msg.content}
                  </span>
                </div>
              ))}
            </div>

            <div style={{ display: "flex", gap: "10px" }}>
              <input
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Type message..."
                style={{ flex: 1, padding: "8px" }}
              />
              <button onClick={sendMessage}>Send</button>
            </div>
          </>
        ) : (
          <p>Select a user to chat</p>
        )}
      </div>
    </div>
  );
}
